-- Singularity Neo capability-scoped standard workflow seed
-- Seeds the standard Enterprise SDLC Flow into existing capabilities.
-- Note:
--   This starter workflow uses the default SDLC phase set. Capabilities that
--   use a custom lifecycle may need the workflow regenerated or adjusted after
--   import.

BEGIN;

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1
    FROM information_schema.tables
    WHERE table_schema = 'public'
      AND table_name = 'capability_workflows'
  ) THEN
    RAISE EXCEPTION 'Table "capability_workflows" does not exist. Load the schema first.';
  END IF;
END $$;

CREATE TEMP TABLE tmp_singularity_seed_capabilities ON COMMIT DROP AS
SELECT
  cap.id AS capability_id,
  LEFT(
    TRIM(
      BOTH '-'
      FROM REGEXP_REPLACE(UPPER(cap.id), '[^A-Z0-9]+', '-', 'g')
    ),
    24
  ) AS capability_slug,
  COALESCE(
    NULLIF(cap.special_agent_id, ''),
    'AGENT-' ||
      LEFT(
        TRIM(
          BOTH '-'
          FROM REGEXP_REPLACE(
            UPPER(COALESCE(NULLIF(cap.name, ''), cap.id, 'CAPABILITY')),
            '[^A-Z0-9]+',
            '-',
            'g'
          )
        ),
        24
      ) ||
      '-OWNER'
  ) AS owner_agent_id
FROM capabilities cap;

WITH workflow_payload AS (
  SELECT
    seed.capability_id,
    seed.capability_slug,
    seed.owner_agent_id,
    REPLACE(
      REPLACE(
        '{"nodes":[{"id":"NODE-CAPABILITYIDTOKEN-START","name":"Start","type":"START","phase":"ANALYSIS","layout":{"x":80,"y":48},"description":"Entry point for the standard SDLC flow."},{"id":"STEP-CAPABILITYIDTOKEN-1","name":"Planning & Stakeholder Synthesis","type":"DELIVERY","phase":"ANALYSIS","layout":{"x":340,"y":48},"agentId":"AGENT-CAPABILITYIDTOKEN-PLANNING","action":"Collect stakeholder and capability inputs, align participating agents, and publish the planning report.","description":"Synthesize stakeholder expectations, capability context, and delivery constraints into a planning report that the rest of the SDLC flow can execute against.","inputArtifactId":"Capability Charter","outputArtifactId":"Planning Report","exitCriteria":["Stakeholder inputs consolidated","Planning report published","Milestone assumptions ready for business analysis"],"templatePath":"/out/steps/planning-step-template.md","allowedToolIds":["workspace_list","workspace_read","workspace_search"],"executionNotes":"Planning should gather capability metadata, stakeholder inputs, and upstream agent context without modifying source code.","artifactContract":{"requiredInputs":["Capability Charter","Stakeholder Requirements","Capability Operating Model","Cross-Agent Input Briefs"],"expectedOutputs":["Planning Report","Delivery Milestone Plan","Stakeholder Alignment Summary","Planning Assumptions Log"],"notes":"Planning should produce a durable synthesis of stakeholder intent, milestones, and cross-agent expectations before detailed analysis begins."}},{"id":"STEP-CAPABILITYIDTOKEN-2","name":"Business Analysis","type":"DELIVERY","phase":"ANALYSIS","layout":{"x":600,"y":48},"agentId":"AGENT-CAPABILITYIDTOKEN-BUSINESS-ANALYST","action":"Refine the story, scope, and acceptance criteria.","description":"Clarify the business outcome, define acceptance criteria, and prepare the story for architecture review.","inputArtifactId":"Capability Charter","outputArtifactId":"Requirements Specification","exitCriteria":["Acceptance criteria approved","Dependencies and assumptions documented","Story ready for solution design"],"templatePath":"/out/steps/analysis-step-template.md","allowedToolIds":["workspace_list","workspace_read","workspace_search"],"executionNotes":"Ground the analysis in capability documentation and repository context. Do not modify source code in this step.","artifactContract":{"requiredInputs":["Capability Charter","Stakeholder Requirements","Planning Report","Stakeholder Priorities Register","Jira Story Context","Domain Constraints Register"],"expectedOutputs":["Requirements Specification","Acceptance Criteria Matrix","Assumptions Log","Dependency Register"],"notes":"Analysis should produce a review-ready business and scope pack that downstream design can trust."}},{"id":"STEP-CAPABILITYIDTOKEN-3","name":"Solution Design","type":"DELIVERY","phase":"DESIGN","layout":{"x":860,"y":224},"agentId":"AGENT-CAPABILITYIDTOKEN-ARCHITECT","action":"Create the technical design and implementation guardrails.","description":"Define the architecture, integration contract, and non-functional expectations before development begins.","inputArtifactId":"Requirements Specification","outputArtifactId":"Solution Design Document","exitCriteria":["Architecture approach documented","Interfaces and dependencies reviewed","Engineering approach approved for build"],"templatePath":"/out/steps/design-step-template.md","allowedToolIds":["workspace_list","workspace_read","workspace_search","git_status"],"executionNotes":"Use repository inspection tools to understand the existing solution shape and produce design guidance before implementation.","artifactContract":{"requiredInputs":["Requirements Specification","Acceptance Criteria Matrix","Architecture Intake Packet","Existing Solution Context"],"expectedOutputs":["Solution Design Document","Architecture Decision Log","API and Integration Contract","Implementation Guardrails"],"notes":"Design should translate business intent into an implementation-ready technical contract."}},{"id":"STEP-CAPABILITYIDTOKEN-4","name":"Implementation","type":"DELIVERY","phase":"DEVELOPMENT","layout":{"x":1120,"y":400},"agentId":"AGENT-CAPABILITYIDTOKEN-SOFTWARE-DEVELOPER","action":"Implement the change and prepare it for validation.","description":"Build the feature, update tests, and produce implementation notes for downstream QA.","inputArtifactId":"Solution Design Document","outputArtifactId":"Code Change Set","exitCriteria":["Code changes completed","Developer checks passed","Build candidate ready for QA"],"templatePath":"/out/steps/development-step-template.md","allowedToolIds":["workspace_list","workspace_read","workspace_search","git_status","workspace_write","run_build","run_test"],"executionNotes":"Implementation can modify files inside capability-approved workspaces and should run build/test validation before completing the step.","artifactContract":{"requiredInputs":["Solution Design Document","Architecture Decision Log","Developer Handoff Packet","Acceptance Criteria Matrix"],"expectedOutputs":["Code Change Set","Developer Test Evidence","Implementation Notes","Build Candidate Manifest"],"notes":"Development should produce both executable change evidence and a clear trace of what was implemented."}},{"id":"STEP-CAPABILITYIDTOKEN-5","name":"Quality Assurance","type":"DELIVERY","phase":"QA","layout":{"x":1380,"y":576},"agentId":"AGENT-CAPABILITYIDTOKEN-QA","action":"Validate the build candidate and collect test evidence.","description":"Run quality validation, regression checks, and document release readiness for governance review.","inputArtifactId":"Build Candidate Manifest","outputArtifactId":"Test Execution Report","exitCriteria":["Test evidence attached","Defects triaged or resolved","Release candidate recommended for governance review"],"templatePath":"/out/steps/qa-step-template.md","allowedToolIds":["workspace_list","workspace_read","workspace_search","git_status","run_test","run_docs"],"executionNotes":"QA should execute configured validation commands, summarize the outcome, and capture evidence for downstream governance.","artifactContract":{"requiredInputs":["Build Candidate Manifest","Acceptance Criteria Matrix","QA Intake Packet","Implementation Notes"],"expectedOutputs":["Test Execution Report","Defect and Risk Log","Release Recommendation","QA Sign-off Notes"],"notes":"QA should produce evidence that explains both the verification outcome and remaining risk posture."}},{"id":"STEP-CAPABILITYIDTOKEN-6","name":"Governance Gate","type":"GOVERNANCE_GATE","phase":"GOVERNANCE","layout":{"x":1640,"y":752},"agentId":"AGENT-CAPABILITYIDTOKEN-VALIDATION","action":"Run governance validation and check release controls.","description":"Validate evidence, policy fit, and hand-off completeness before moving into human approval.","inputArtifactId":"Validation Evidence Pack","outputArtifactId":"Governance Assessment","governanceGate":"Release Governance Gate","approverRoles":["Development Manager","Team Lead"],"exitCriteria":["Validation report completed","Required evidence attached","Governance gate cleared for approval"],"templatePath":"/out/steps/governance-gate-template.md","allowedToolIds":["workspace_read","workspace_search","run_docs"],"executionNotes":"Governance validation should review evidence and produce approval-ready documentation, but it should not perform deployments.","artifactContract":{"requiredInputs":["Validation Evidence Pack","Governance Review Summary","Defect and Risk Log","Release Recommendation"],"expectedOutputs":["Governance Assessment","Risk and Control Record","Policy Exception Log","Approval Brief"],"notes":"Governance must distill all release evidence into an approval-ready control package."}},{"id":"STEP-CAPABILITYIDTOKEN-7","name":"Human Approval","type":"HUMAN_APPROVAL","phase":"RELEASE","layout":{"x":1900,"y":928},"agentId":"OWNERAGENTTOKEN","action":"Obtain human approval for release promotion.","description":"Collect final human sign-off and confirm the release decision before handing to DevOps.","inputArtifactId":"Human Approval Packet","outputArtifactId":"Approval Decision Record","approverRoles":["Development Manager","Squad Leader","Team Lead"],"exitCriteria":["Human approval captured","Release decision documented","Deployment cleared to proceed"],"templatePath":"/out/steps/human-approval-template.md","allowedToolIds":[],"executionNotes":"This step always pauses for explicit human approval. The backend runner must not auto-complete it.","artifactContract":{"requiredInputs":["Human Approval Packet","Release Readiness Record","Rollback Plan","Release Window Details"],"expectedOutputs":["Approval Decision Record","Release Authorization","Approver Comments Log"],"notes":"Human approval should capture a durable authorization record and any release conditions or comments."}},{"id":"STEP-CAPABILITYIDTOKEN-8","name":"Release Execution","type":"RELEASE","phase":"RELEASE","layout":{"x":2160,"y":928},"agentId":"AGENT-CAPABILITYIDTOKEN-DEVOPS","action":"Deploy, verify, and close the release.","description":"Execute deployment, verify the release, and publish the final operational status.","inputArtifactId":"Deployment Authorization Packet","outputArtifactId":"Deployment Summary","exitCriteria":["Deployment completed","Operational verification passed","Release summary published"],"templatePath":"/out/steps/release-step-template.md","allowedToolIds":["workspace_read","git_status","run_deploy","run_docs"],"executionNotes":"Release execution can only use capability-configured deployment/doc commands and must remain approval-gated before deployment starts.","artifactContract":{"requiredInputs":["Deployment Authorization Packet","Release Authorization","Deployment Plan","Rollback Plan"],"expectedOutputs":["Deployment Summary","Production Verification Report","Release Notes","Hypercare Handoff"],"notes":"Release execution should leave behind a complete operational record of what was deployed and how it verified."}},{"id":"NODE-CAPABILITYIDTOKEN-END","name":"End","type":"END","phase":"RELEASE","layout":{"x":2420,"y":928},"description":"Terminal completion node for the workflow."}],"edges":[{"id":"EDGE-R0JERK20","fromNodeId":"NODE-CAPABILITYIDTOKEN-START","toNodeId":"STEP-CAPABILITYIDTOKEN-1","label":"Begin SDLC delivery","conditionType":"DEFAULT"},{"id":"EDGE-6J32Y52E","fromNodeId":"STEP-CAPABILITYIDTOKEN-1","toNodeId":"STEP-CAPABILITYIDTOKEN-2","label":"Planning hand-off to business analysis","conditionType":"DEFAULT","handoffProtocolId":"HANDOFF-CAPABILITYIDTOKEN-PLANNING","artifactContract":{"requiredInputs":["Planning Report","Delivery Milestone Plan","Planning Assumptions Log"],"expectedOutputs":["Analysis Intake Packet","Stakeholder Priorities Register"],"notes":"Package the planning baseline so business analysis starts with agreed priorities, milestones, and assumptions."}},{"id":"EDGE-WPHBRH54","fromNodeId":"STEP-CAPABILITYIDTOKEN-2","toNodeId":"STEP-CAPABILITYIDTOKEN-3","label":"Requirements hand-off to architecture","conditionType":"DEFAULT","handoffProtocolId":"HANDOFF-CAPABILITYIDTOKEN-ANALYSIS","artifactContract":{"requiredInputs":["Requirements Specification","Acceptance Criteria Matrix","Assumptions Log","Planning Report"],"expectedOutputs":["Architecture Intake Packet","Open Questions for Design"],"notes":"Package the refined story intent and unresolved assumptions for architecture review."}},{"id":"EDGE-8XRBBH4P","fromNodeId":"STEP-CAPABILITYIDTOKEN-3","toNodeId":"STEP-CAPABILITYIDTOKEN-4","label":"Design hand-off to development","conditionType":"DEFAULT","handoffProtocolId":"HANDOFF-CAPABILITYIDTOKEN-DESIGN","artifactContract":{"requiredInputs":["Solution Design Document","Architecture Decision Log","Implementation Guardrails"],"expectedOutputs":["Developer Handoff Packet","Build Scope Breakdown"],"notes":"Give development a precise build plan, contract boundaries, and design decisions."}},{"id":"EDGE-T1QVF0R8","fromNodeId":"STEP-CAPABILITYIDTOKEN-4","toNodeId":"STEP-CAPABILITYIDTOKEN-5","label":"Implementation hand-off to QA","conditionType":"DEFAULT","handoffProtocolId":"HANDOFF-CAPABILITYIDTOKEN-DEVELOPMENT","artifactContract":{"requiredInputs":["Code Change Set","Developer Test Evidence","Build Candidate Manifest"],"expectedOutputs":["QA Intake Packet","Regression Focus Areas"],"notes":"Package the build candidate, developer validation, and risk notes for QA."}},{"id":"EDGE-CAU6N0UO","fromNodeId":"STEP-CAPABILITYIDTOKEN-5","toNodeId":"STEP-CAPABILITYIDTOKEN-6","label":"QA evidence hand-off to validation","conditionType":"DEFAULT","handoffProtocolId":"HANDOFF-CAPABILITYIDTOKEN-QA","artifactContract":{"requiredInputs":["Test Execution Report","Defect and Risk Log","Release Recommendation"],"expectedOutputs":["Validation Evidence Pack","Governance Review Summary"],"notes":"Move structured evidence and quality posture into governance review."}},{"id":"EDGE-8H2FUSYI","fromNodeId":"STEP-CAPABILITYIDTOKEN-6","toNodeId":"STEP-CAPABILITYIDTOKEN-7","label":"Governance gate hand-off to capability owner","conditionType":"DEFAULT","handoffProtocolId":"HANDOFF-CAPABILITYIDTOKEN-GOVERNANCE","artifactContract":{"requiredInputs":["Governance Assessment","Approval Brief","Risk and Control Record"],"expectedOutputs":["Human Approval Packet","Release Readiness Record"],"notes":"Prepare the final approval packet with the exact decision context needed by human approvers."}},{"id":"EDGE-ADL9BCGI","fromNodeId":"STEP-CAPABILITYIDTOKEN-7","toNodeId":"STEP-CAPABILITYIDTOKEN-8","label":"Approved release hand-off to DevOps","conditionType":"DEFAULT","handoffProtocolId":"HANDOFF-CAPABILITYIDTOKEN-APPROVAL","artifactContract":{"requiredInputs":["Release Authorization","Approval Decision Record","Rollback Plan"],"expectedOutputs":["Deployment Authorization Packet","Operational Readiness Notes"],"notes":"Translate human approval into a deployment-ready hand-off for release execution."}},{"id":"EDGE-30AHYVFB","fromNodeId":"STEP-CAPABILITYIDTOKEN-8","toNodeId":"NODE-CAPABILITYIDTOKEN-END","label":"Release completion hand-off to capability owner","conditionType":"DEFAULT","handoffProtocolId":"HANDOFF-CAPABILITYIDTOKEN-RELEASE","artifactContract":{"requiredInputs":["Deployment Summary","Production Verification Report","Release Notes"],"expectedOutputs":["Capability Closure Packet","Post-Release Follow-up List"],"notes":"Close the workflow with a final operational and ownership hand-off back to the capability owner."}}],"steps":[{"id":"STEP-CAPABILITYIDTOKEN-1","name":"Planning & Stakeholder Synthesis","phase":"ANALYSIS","stepType":"DELIVERY","agentId":"AGENT-CAPABILITYIDTOKEN-PLANNING","action":"Collect stakeholder and capability inputs, align participating agents, and publish the planning report.","description":"Synthesize stakeholder expectations, capability context, and delivery constraints into a planning report that the rest of the SDLC flow can execute against.","inputArtifactId":"Capability Charter","outputArtifactId":"Planning Report","handoffToAgentId":"AGENT-CAPABILITYIDTOKEN-BUSINESS-ANALYST","handoffToPhase":"ANALYSIS","handoffLabel":"Planning hand-off to business analysis","handoffProtocolId":"HANDOFF-CAPABILITYIDTOKEN-PLANNING","exitCriteria":["Stakeholder inputs consolidated","Planning report published","Milestone assumptions ready for business analysis"],"templatePath":"/out/steps/planning-step-template.md","allowedToolIds":["workspace_list","workspace_read","workspace_search"],"executionNotes":"Planning should gather capability metadata, stakeholder inputs, and upstream agent context without modifying source code.","artifactContract":{"requiredInputs":["Capability Charter","Stakeholder Requirements","Capability Operating Model","Cross-Agent Input Briefs"],"expectedOutputs":["Planning Report","Delivery Milestone Plan","Stakeholder Alignment Summary","Planning Assumptions Log"],"notes":"Planning should produce a durable synthesis of stakeholder intent, milestones, and cross-agent expectations before detailed analysis begins."}},{"id":"STEP-CAPABILITYIDTOKEN-2","name":"Business Analysis","phase":"ANALYSIS","stepType":"DELIVERY","agentId":"AGENT-CAPABILITYIDTOKEN-BUSINESS-ANALYST","action":"Refine the story, scope, and acceptance criteria.","description":"Clarify the business outcome, define acceptance criteria, and prepare the story for architecture review.","inputArtifactId":"Capability Charter","outputArtifactId":"Requirements Specification","handoffToAgentId":"AGENT-CAPABILITYIDTOKEN-ARCHITECT","handoffToPhase":"DESIGN","handoffLabel":"Requirements hand-off to architecture","handoffProtocolId":"HANDOFF-CAPABILITYIDTOKEN-ANALYSIS","exitCriteria":["Acceptance criteria approved","Dependencies and assumptions documented","Story ready for solution design"],"templatePath":"/out/steps/analysis-step-template.md","allowedToolIds":["workspace_list","workspace_read","workspace_search"],"executionNotes":"Ground the analysis in capability documentation and repository context. Do not modify source code in this step.","artifactContract":{"requiredInputs":["Capability Charter","Stakeholder Requirements","Planning Report","Stakeholder Priorities Register","Jira Story Context","Domain Constraints Register"],"expectedOutputs":["Requirements Specification","Acceptance Criteria Matrix","Assumptions Log","Dependency Register"],"notes":"Analysis should produce a review-ready business and scope pack that downstream design can trust."}},{"id":"STEP-CAPABILITYIDTOKEN-3","name":"Solution Design","phase":"DESIGN","stepType":"DELIVERY","agentId":"AGENT-CAPABILITYIDTOKEN-ARCHITECT","action":"Create the technical design and implementation guardrails.","description":"Define the architecture, integration contract, and non-functional expectations before development begins.","inputArtifactId":"Requirements Specification","outputArtifactId":"Solution Design Document","handoffToAgentId":"AGENT-CAPABILITYIDTOKEN-SOFTWARE-DEVELOPER","handoffToPhase":"DEVELOPMENT","handoffLabel":"Design hand-off to development","handoffProtocolId":"HANDOFF-CAPABILITYIDTOKEN-DESIGN","exitCriteria":["Architecture approach documented","Interfaces and dependencies reviewed","Engineering approach approved for build"],"templatePath":"/out/steps/design-step-template.md","allowedToolIds":["workspace_list","workspace_read","workspace_search","git_status"],"executionNotes":"Use repository inspection tools to understand the existing solution shape and produce design guidance before implementation.","artifactContract":{"requiredInputs":["Requirements Specification","Acceptance Criteria Matrix","Architecture Intake Packet","Existing Solution Context"],"expectedOutputs":["Solution Design Document","Architecture Decision Log","API and Integration Contract","Implementation Guardrails"],"notes":"Design should translate business intent into an implementation-ready technical contract."}},{"id":"STEP-CAPABILITYIDTOKEN-4","name":"Implementation","phase":"DEVELOPMENT","stepType":"DELIVERY","agentId":"AGENT-CAPABILITYIDTOKEN-SOFTWARE-DEVELOPER","action":"Implement the change and prepare it for validation.","description":"Build the feature, update tests, and produce implementation notes for downstream QA.","inputArtifactId":"Solution Design Document","outputArtifactId":"Code Change Set","handoffToAgentId":"AGENT-CAPABILITYIDTOKEN-QA","handoffToPhase":"QA","handoffLabel":"Implementation hand-off to QA","handoffProtocolId":"HANDOFF-CAPABILITYIDTOKEN-DEVELOPMENT","exitCriteria":["Code changes completed","Developer checks passed","Build candidate ready for QA"],"templatePath":"/out/steps/development-step-template.md","allowedToolIds":["workspace_list","workspace_read","workspace_search","git_status","workspace_write","run_build","run_test"],"executionNotes":"Implementation can modify files inside capability-approved workspaces and should run build/test validation before completing the step.","artifactContract":{"requiredInputs":["Solution Design Document","Architecture Decision Log","Developer Handoff Packet","Acceptance Criteria Matrix"],"expectedOutputs":["Code Change Set","Developer Test Evidence","Implementation Notes","Build Candidate Manifest"],"notes":"Development should produce both executable change evidence and a clear trace of what was implemented."}},{"id":"STEP-CAPABILITYIDTOKEN-5","name":"Quality Assurance","phase":"QA","stepType":"DELIVERY","agentId":"AGENT-CAPABILITYIDTOKEN-QA","action":"Validate the build candidate and collect test evidence.","description":"Run quality validation, regression checks, and document release readiness for governance review.","inputArtifactId":"Build Candidate Manifest","outputArtifactId":"Test Execution Report","handoffToAgentId":"AGENT-CAPABILITYIDTOKEN-VALIDATION","handoffToPhase":"GOVERNANCE","handoffLabel":"QA evidence hand-off to validation","handoffProtocolId":"HANDOFF-CAPABILITYIDTOKEN-QA","exitCriteria":["Test evidence attached","Defects triaged or resolved","Release candidate recommended for governance review"],"templatePath":"/out/steps/qa-step-template.md","allowedToolIds":["workspace_list","workspace_read","workspace_search","git_status","run_test","run_docs"],"executionNotes":"QA should execute configured validation commands, summarize the outcome, and capture evidence for downstream governance.","artifactContract":{"requiredInputs":["Build Candidate Manifest","Acceptance Criteria Matrix","QA Intake Packet","Implementation Notes"],"expectedOutputs":["Test Execution Report","Defect and Risk Log","Release Recommendation","QA Sign-off Notes"],"notes":"QA should produce evidence that explains both the verification outcome and remaining risk posture."}},{"id":"STEP-CAPABILITYIDTOKEN-6","name":"Governance Gate","phase":"GOVERNANCE","stepType":"GOVERNANCE_GATE","agentId":"AGENT-CAPABILITYIDTOKEN-VALIDATION","action":"Run governance validation and check release controls.","description":"Validate evidence, policy fit, and hand-off completeness before moving into human approval.","inputArtifactId":"Validation Evidence Pack","outputArtifactId":"Governance Assessment","handoffToAgentId":"OWNERAGENTTOKEN","handoffToPhase":"RELEASE","handoffLabel":"Governance gate hand-off to capability owner","handoffProtocolId":"HANDOFF-CAPABILITYIDTOKEN-GOVERNANCE","governanceGate":"Release Governance Gate","approverRoles":["Development Manager","Team Lead"],"exitCriteria":["Validation report completed","Required evidence attached","Governance gate cleared for approval"],"templatePath":"/out/steps/governance-gate-template.md","allowedToolIds":["workspace_read","workspace_search","run_docs"],"executionNotes":"Governance validation should review evidence and produce approval-ready documentation, but it should not perform deployments.","artifactContract":{"requiredInputs":["Validation Evidence Pack","Governance Review Summary","Defect and Risk Log","Release Recommendation"],"expectedOutputs":["Governance Assessment","Risk and Control Record","Policy Exception Log","Approval Brief"],"notes":"Governance must distill all release evidence into an approval-ready control package."}},{"id":"STEP-CAPABILITYIDTOKEN-7","name":"Human Approval","phase":"RELEASE","stepType":"HUMAN_APPROVAL","agentId":"OWNERAGENTTOKEN","action":"Obtain human approval for release promotion.","description":"Collect final human sign-off and confirm the release decision before handing to DevOps.","inputArtifactId":"Human Approval Packet","outputArtifactId":"Approval Decision Record","handoffToAgentId":"AGENT-CAPABILITYIDTOKEN-DEVOPS","handoffToPhase":"RELEASE","handoffLabel":"Approved release hand-off to DevOps","handoffProtocolId":"HANDOFF-CAPABILITYIDTOKEN-APPROVAL","approverRoles":["Development Manager","Squad Leader","Team Lead"],"exitCriteria":["Human approval captured","Release decision documented","Deployment cleared to proceed"],"templatePath":"/out/steps/human-approval-template.md","allowedToolIds":[],"executionNotes":"This step always pauses for explicit human approval. The backend runner must not auto-complete it.","artifactContract":{"requiredInputs":["Human Approval Packet","Release Readiness Record","Rollback Plan","Release Window Details"],"expectedOutputs":["Approval Decision Record","Release Authorization","Approver Comments Log"],"notes":"Human approval should capture a durable authorization record and any release conditions or comments."}},{"id":"STEP-CAPABILITYIDTOKEN-8","name":"Release Execution","phase":"RELEASE","stepType":"DELIVERY","agentId":"AGENT-CAPABILITYIDTOKEN-DEVOPS","action":"Deploy, verify, and close the release.","description":"Execute deployment, verify the release, and publish the final operational status.","inputArtifactId":"Deployment Authorization Packet","outputArtifactId":"Deployment Summary","handoffLabel":"Release completion hand-off to capability owner","handoffProtocolId":"HANDOFF-CAPABILITYIDTOKEN-RELEASE","exitCriteria":["Deployment completed","Operational verification passed","Release summary published"],"templatePath":"/out/steps/release-step-template.md","allowedToolIds":["workspace_read","git_status","run_deploy","run_docs"],"executionNotes":"Release execution can only use capability-configured deployment/doc commands and must remain approval-gated before deployment starts.","artifactContract":{"requiredInputs":["Deployment Authorization Packet","Release Authorization","Deployment Plan","Rollback Plan"],"expectedOutputs":["Deployment Summary","Production Verification Report","Release Notes","Hypercare Handoff"],"notes":"Release execution should leave behind a complete operational record of what was deployed and how it verified."}}]}',
        'OWNERAGENTTOKEN',
        seed.owner_agent_id
      ),
      'CAPABILITYIDTOKEN',
      seed.capability_slug
    )::jsonb AS payload
  FROM tmp_singularity_seed_capabilities seed
)
INSERT INTO capability_workflows (
  capability_id,
  id,
  name,
  status,
  workflow_type,
  scope,
  summary,
  schema_version,
  entry_node_id,
  nodes,
  edges,
  steps,
  publish_state,
  created_at,
  updated_at
)
SELECT
  capability_id,
  'WF-' || capability_slug || '-STANDARD-SDLC',
  'Enterprise SDLC Flow',
  'STABLE',
  'SDLC',
  'CAPABILITY',
  'Standard SDLC workflow with explicit agent hand-offs, standard input/output document artifacts, governance validation, and human approval before release.',
  2,
  'NODE-' || capability_slug || '-START',
  payload->'nodes',
  payload->'edges',
  payload->'steps',
  'PUBLISHED',
  NOW(),
  NOW()
FROM workflow_payload
ON CONFLICT (capability_id, id) DO UPDATE SET
  name = EXCLUDED.name,
  status = EXCLUDED.status,
  workflow_type = EXCLUDED.workflow_type,
  scope = EXCLUDED.scope,
  summary = EXCLUDED.summary,
  schema_version = EXCLUDED.schema_version,
  entry_node_id = EXCLUDED.entry_node_id,
  nodes = EXCLUDED.nodes,
  edges = EXCLUDED.edges,
  steps = EXCLUDED.steps,
  publish_state = EXCLUDED.publish_state,
  updated_at = NOW();

COMMIT;
